// Build the analysis prompt
// The binary file data from GCS download is available for Gemini
const webhookData = $('Webhook Trigger').first().json;

const prompt = `You are a compliance document analyzer. Extract structured metadata from this document.

Return ONLY valid JSON (no markdown fences) with these fields:
{
  "document_name": "formal name/title of the document",
  "document_type": "contract|agreement|license|permit|certificate|policy|invoice|report|other",
  "category": "legal|insurance|regulatory|safety|financial|hr|environmental|other",
  "company_name": "primary company/organization name in the document",
  "effective_date": "YYYY-MM-DD or null",
  "expiry_date": "YYYY-MM-DD or null (if not explicitly stated, estimate from effective_date + standard term)",
  "party_a": "the party the document belongs to / first party",
  "party_b": "the counterparty / second party",
  "summary": "2-3 sentence summary of the document's purpose and key terms",
  "keywords": ["keyword1", "keyword2", ...],
  "jurisdiction": "legal jurisdiction if mentioned, or null",
  "key_clauses": [{"name": "clause name", "summary": "brief description"}],
  "monetary_amounts": [{"description": "what for", "amount": "$X", "currency": "USD"}],
  "compliance_requirements": ["requirement 1", "requirement 2"],
  "risk_flags": ["any concerning terms, missing standard clauses, or compliance risks"]
}`;

return [{
  json: {
    ...webhookData,
    prompt: prompt
  }
}];

// Parse Gemini response and normalize all extracted data
const geminiOutput = $input.first().json;
const webhookData = $('Webhook Trigger').first().json;

let extracted = {};
try {
  let text = '';
  // Handle various Gemini response formats
  if (typeof geminiOutput === 'string') {
    text = geminiOutput;
  } else if (geminiOutput.text) {
    text = geminiOutput.text;
  } else if (geminiOutput.output) {
    text = geminiOutput.output;
  } else if (geminiOutput.candidates) {
    text = geminiOutput.candidates[0].content.parts[0].text;
  } else {
    text = JSON.stringify(geminiOutput);
  }

  // Clean markdown code fences
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  extracted = JSON.parse(text);
} catch (e) {
  extracted = {
    document_name: webhookData.filename || 'Unknown',
    document_type: webhookData.document_type || 'other',
    category: 'other',
    company_name: '',
    effective_date: null,
    expiry_date: null,
    party_a: '',
    party_b: '',
    summary: 'Automated extraction failed - manual review recommended.',
    keywords: [],
    jurisdiction: null,
    key_clauses: [],
    monetary_amounts: [],
    compliance_requirements: [],
    risk_flags: ['extraction_failed']
  };
}

// Normalize dates to YYYY-MM-DD
function normalizeDate(d) {
  if (!d) return null;
  // Already ISO
  if (/^\d{4}-\d{2}-\d{2}/.test(d)) return d.substring(0, 10);
  // mm-dd-yyyy or mm/dd/yyyy
  const m = d.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m) return `${m[3]}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}`;
  return d;
}

const result = {
  document_id: webhookData.document_id,
  entity_id: webhookData.entity_id,
  organization_id: webhookData.organization_id || '',
  filename: webhookData.filename,
  gcs_path: webhookData.gcs_path,
  gcs_bucket: webhookData.gcs_bucket,

  // Gemini-extracted fields
  document_name: extracted.document_name || webhookData.filename,
  document_type_detected: extracted.document_type || webhookData.document_type,
  category: extracted.category || 'other',
  company_name: extracted.company_name || '',
  effective_date: normalizeDate(extracted.effective_date),
  expiry_date: normalizeDate(extracted.expiry_date),
  party_a: extracted.party_a || '',
  party_b: extracted.party_b || '',
  ai_summary: extracted.summary || '',
  ai_tags: extracted.keywords || [],
  jurisdiction: extracted.jurisdiction || null,
  key_clauses: extracted.key_clauses || [],
  monetary_amounts: extracted.monetary_amounts || [],
  compliance_requirements: extracted.compliance_requirements || [],
  risk_flags: extracted.risk_flags || [],

  processed_at: new Date().toISOString()
};

return [{ json: result }];

